import json

# ── STEP 1: extract and verify every INPUT entity from the evidence ─────────
entities = []

# Segment 1 — "the BUN is 9.8 mg/dL"
claim_bun    = 9.8
evidence_bun = 9.8
correct_bun  = (claim_bun >= 18.2 and claim_bun <= 22.3) or (claim_bun >= 22.4 and claim_bun <= 28) or (claim_bun >= 28 and claim_bun <= 70) or (claim_bun > 70)
entities.append({
    "name": "BUN", "claim_value": "9.8 mg/dL",
    "evidence_value": "9.8 mg/dL", "correct": correct_bun
})

# Segment 2 — "the Hemoglobin is 9.5 g/dL"
claim_hemoglobin    = 9.5
evidence_hemoglobin = 9.5
correct_hemoglobin_men  = (claim_hemoglobin >= 13)
correct_hemoglobin_women = (claim_hemoglobin >= 12)
correct_hemoglobin = correct_hemoglobin_men or correct_hemoglobin_women
entities.append({
    "name": "Hemoglobin", "claim_value": "9.5 g/dL",
    "evidence_value": "9.5 g/dL", "correct": correct_hemoglobin
})

# Segment 3 — "the Systolic BP is 116 mm Hg"
claim_systolic_bp    = 116
evidence_systolic_bp = 116
correct_systolic_bp  = (claim_systolic_bp >= 110)
entities.append({
    "name": "Systolic BP", "claim_value": "116 mm Hg",
    "evidence_value": "116 mm Hg", "correct": correct_systolic_bp
})

# Segment 4 — "the Heart Rate is no"
claim_heart_rate    = "no"
evidence_heart_rate = "no"
correct_heart_rate  = (claim_heart_rate == "no")
entities.append({
    "name": "Heart Rate", "claim_value": "no",
    "evidence_value": "no", "correct": correct_heart_rate
})

# Segment 5 — "the Melena is yes"
claim_melena    = "yes"
evidence_melena = "yes"
correct_melena  = (claim_melena == "yes")
entities.append({
    "name": "Melena", "claim_value": "yes",
    "evidence_value": "yes", "correct": correct_melena
})

# Segment 6 — "the Syncope is no"
claim_syncope    = "no"
evidence_syncope = "no"
correct_syncope  = (claim_syncope == "no")
entities.append({
    "name": "Syncope", "claim_value": "no",
    "evidence_value": "no", "correct": correct_syncope
})

# Segment 7 — "the Hepatic Disease is no"
claim_hepatic_disease    = "no"
evidence_hepatic_disease = "no"
correct_hepatic_disease  = (claim_hepatic_disease == "no")
entities.append({
    "name": "Hepatic Disease", "claim_value": "no",
    "evidence_value": "no", "correct": correct_hepatic_disease
})

# Segment 8 — "the Cardiac Failure is no"
claim_cardiac_failure    = "no"
evidence_cardiac_failure = "no"
correct_cardiac_failure  = (claim_cardiac_failure == "no")
entities.append({
    "name": "Cardiac Failure", "claim_value": "no",
    "evidence_value": "no", "correct": correct_cardiac_failure
})

# ── STEP 2: calculate using evidence values ─────────────────────────────────
calculator_type = "rule-based"
formula         = "Glasgow-Blatchford Bleeding Score = BUN + Hemoglobin + Systolic BP + Heart Rate + Melena + Syncope + Hepatic Disease + Cardiac Failure"
substitution    = f"{int(correct_bun)} + {int(correct_hemoglobin)} + {int(correct_systolic_bp)} + {int(correct_heart_rate)} + {int(correct_melena)} + {int(correct_syncope)} + {int(correct_hepatic_disease)} + {int(correct_cardiac_failure)}"

# Calculate points for each criterion
bun_points = 0
if claim_bun >= 70:
    bun_points = 6
elif claim_bun >= 28:
    bun_points = 4
elif claim_bun >= 22.4:
    bun_points = 3
elif claim_bun >= 18.2:
    bun_points = 2
else:
    bun_points = 0

hemoglobin_points_men = 0
if claim_hemoglobin < 10:
    hemoglobin_points_men = 6
elif claim_hemoglobin <= 12:
    hemoglobin_points_men = 3
elif claim_hemoglobin <= 13:
    hemoglobin_points_men = 1
else:
    hemoglobin_points_men = 0

hemoglobin_points_women = 0
if claim_hemoglobin < 10:
    hemoglobin_points_women = 6
elif claim_hemoglobin <= 12:
    hemoglobin_points_women = 1
else:
    hemoglobin_points_women = 0

systolic_bp_points = 0
if claim_systolic_bp < 90:
    systolic_bp_points = 3
elif claim_systolic_bp <= 99:
    systolic_bp_points = 2
elif claim_systolic_bp <= 109:
    systolic_bp_points = 1
else:
    systolic_bp_points = 0

heart_rate_points = 0
if claim_heart_rate == "yes":
    heart_rate_points = 1
else:
    heart_rate_points = 0

melena_points = 0
if claim_melena == "yes":
    melena_points = 1
else:
    melena_points = 0

syncope_points = 0
if claim_syncope == "yes":
    syncope_points = 1
else:
    syncope_points = 0

hepatic_disease_points = 0
if claim_hepatic_disease == "yes":
    hepatic_disease_points = 1
else:
    hepatic_disease_points = 0

cardiac_failure_points = 0
if claim_cardiac_failure == "yes":
    cardiac_failure_points = 1
else:
    cardiac_failure_points = 0

# Calculate the final score
final_score = bun_points + hemoglobin_points_men + systolic_bp_points + heart_rate_points + melena_points + syncope_points + hepatic_disease_points + cardiac_failure_points

calculation = {
    "calculator_type": calculator_type,
    "formula":         formula,
    "substitution":    substitution,
    "steps":           f"{substitution} = {final_score}",
    "correct_result":  f"{final_score}",
    "claimed_result":  7,
    "correct":         (final_score == 7),
}

# ── STEP 3: derive label ────────────────────────────────────────────────────
all_step1_correct = all(e["correct"] for e in entities)
if all_step1_correct and calculation["correct"]:
    label = "true"
elif all_step1_correct and not calculation["correct"]:
    label = "partially true"
else:
    label = "false"

print(json.dumps({
    "step1_entities":    entities,
    "step2_calculation": calculation,
    "step3_label":       label,
}))

