import json

# ── STEP 1: extract and verify every INPUT entity from the evidence ─────────
entities = []

# Segment 1 — "the nervous is yes"
nervous_present = True
entities.append({
    "name": "Nervous", "claim_value": "yes",
    "evidence_value": "yes", "correct": nervous_present
})

# Segment 2 — "the control_worrying is no"
control_worrying_present = False
entities.append({
    "name": "Control Worrying", "claim_value": "no",
    "evidence_value": "no", "correct": control_worrying_present
})

# Segment 3 — "the worry_too_much is yes"
worry_too_much_present = True
entities.append({
    "name": "Worry Too Much", "claim_value": "yes",
    "evidence_value": "yes", "correct": worry_too_much_present
})

# Segment 4 — "the trouble_relaxing is 3"
trouble_relaxing = 3
entities.append({
    "name": "Trouble Relaxing", "claim_value": "3",
    "evidence_value": "3", "correct": (trouble_relaxing == 3)
})

# Segment 5 — "the restlessness is yes"
restlessness_present = True
entities.append({
    "name": "Restlessness", "claim_value": "yes",
    "evidence_value": "yes", "correct": restlessness_present
})

# Segment 6 — "the irritability is no"
irritability_present = False
entities.append({
    "name": "Irritability", "claim_value": "no",
    "evidence_value": "no", "correct": irritability_present
})

# Segment 7 — "the fear_of_awful_events is yes"
fear_of_awful_events_present = True
entities.append({
    "name": "Fear of Awful Events", "claim_value": "yes",
    "evidence_value": "yes", "correct": fear_of_awful_events_present
})

# Segment 8 — "the GAD-7 Score is 7"
gad7_score = 7
entities.append({
    "name": "GAD-7 Score", "claim_value": "7",
    "evidence_value": "7", "correct": (gad7_score == 7)
})

# ── STEP 2: calculate using evidence values ─────────────────────────────────
# Formula: Glasgow Coma Scale (GCS) = Best Eye Response + Best Verbal Response + Best Motor Response
calculator_type = "rule-based"
formula         = "Glasgow Coma Scale (GCS) = Best Eye Response + Best Verbal Response + Best Motor Response"

# Best Eye Response
best_eye_response = 0
if nervous_present:
    best_eye_response = 4
elif control_worrying_present:
    best_eye_response = 3
elif worry_too_much_present:
    best_eye_response = 2
else:
    best_eye_response = 1

# Best Verbal Response
best_verbal_response = 0
if irritability_present:
    best_verbal_response = 1
else:
    best_verbal_response = 5

# Best Motor Response
best_motor_response = 0
if restlessness_present:
    best_motor_response = 4
elif fear_of_awful_events_present:
    best_motor_response = 5
elif trouble_relaxing == 3:
    best_motor_response = 3
else:
    best_motor_response = 1

# Accuracy criterion — rule-based → exact match
gcs_score = best_eye_response + best_verbal_response + best_motor_response
claimed_result_val = 7  # last claim segment

calculation = {
    "calculator_type": calculator_type,
    "formula":         formula,
    "substitution":    f"{best_eye_response} + {best_verbal_response} + {best_motor_response}",
    "steps":           f"{best_eye_response} + {best_verbal_response} + {best_motor_response} = {gcs_score}",
    "correct_result":  f"{gcs_score}",
    "claimed_result":  f"{claimed_result_val}",
    "correct":         (gcs_score == claimed_result_val),
}

# ── STEP 3: derive label ────────────────────────────────────────────────────
all_step1_correct = all(e["correct"] for e in entities)
if all_step1_correct and calculation["correct"]:
    label = "true"
elif all_step1_correct and not calculation["correct"]:
    label = "partially true"
else:
    label = "false"

print(json.dumps({
    "step1_entities":    entities,
    "step2_calculation": calculation,
    "step3_label":       label,
}))

