# ── STEP 2: calculate using evidence values ─────────────────────────────────
# Formula: PSI = sum of points for each criterion
calculator_type = "rule-based"
formula         = "Pneumonia Severity Index (PSI) = sum of points for each criterion"

# Pattern A — binary (Yes/No, Present/Absent)
def confusion_points(confusion_present):
    return 1 if confusion_present else 0

def dvt_signs_points(dvt_signs_present):
    return 3 if dvt_signs_present else 0

def history_of_severe_organ_insufficiency_points(hosi):
    return 10 if hosi else 0

def acute_renal_failure_points(arf):
    return 10 if arf else 0

# Pattern B — tiered range (multiple score levels)
def age_points(age):
    if age >= 75:
        return 2
    elif age >= 65:
        return 1
    else:
        return 0

def temperature_points(temp):
    if temp < 35:
        return 15
    elif temp > 39.9:
        return 15
    else:
        return 0

def heart_rate_points(hr):
    if hr >= 125:
        return 10
    else:
        return 0

def respiratory_rate_points(rr):
    if rr >= 30:
        return 20
    else:
        return 0

def systolic_blood_pressure_points(sbp):
    if sbp < 90:
        return 20
    else:
        return 0

def sodium_points(sodium):
    if sodium < 130:
        return 20
    else:
        return 0

def potassium_points(potassium):
    if potassium < 3.5:
        return 1
    elif potassium < 5.5:
        return 2
    elif potassium < 6.5:
        return 3
    else:
        return 0

def creatinine_points(creatinine):
    if creatinine >= 2:
        return 6
    elif creatinine >= 1.2:
        return 5
    elif creatinine >= 1:
        return 4
    elif creatinine >= 0.8:
        return 3
    elif creatinine >= 0.6:
        return 2
    elif creatinine >= 0.4:
        return 1
    else:
        return 0

def hematocrit_points(hct):
    if hct < 30:
        return 10
    else:
        return 0

def white_blood_cell_count_points(wbc):
    if wbc >= 40 * (10**9):
        return 1
    elif wbc >= 20 * (10**9):
        return 0.33
    else:
        return 0

def gcs_points(gcs):
    if gcs <= 3:
        return 3
    elif gcs <= 8:
        return 2
    else:
        return 1

def ph_points(ph):
    if ph < 7.35:
        return 30
    else:
        return 0

def fio2_points(fio2):
    if fio2 >= 60:
        return 1
    else:
        return 0

def a_a_gradient_points(aag):
    if aag >= 500:
        return 1
    else:
        return 0

def apache_ii_points(apache):
    if apache >= 25:
        return 1
    else:
        return 0

# Pattern C — direct numeric value
def age_points_direct(age):
    return age

# Calculate points for each criterion
age_points_value = age_points_direct(evidence_age)
sex_points_value = 0  # Male = 0 points
nursing_home_resident_points_value = 0  # No = 0 points
neoplastic_disease_points_value = 0  # No = 0 points
liver_disease_history_points_value = 0  # No = 0 points
chf_history_points_value = 0  # No = 0 points
cerebrovascular_disease_history_points_value = 0  # No = 0 points
renal_disease_history_points_value = 0  # No = 0 points
altered_mental_status_points_value = 0  # No = 0 points
respiratory_rate_ge_30_points_value = respiratory_rate_points(evidence_rr)
systolic_blood_pressure_lt_90_points_value = systolic_blood_pressure_points(evidence_map)
temperature_lt_35_or_gt_39_9_points_value = temperature_points(evidence_temp)
pulse_ge_125_points_value = heart_rate_points(evidence_hr)
pH_lt_7_35_points_value = ph_points(claim_ph)
bun_ge_30_mg_dl_or_ge_11_mmol_l_points_value = 0  # No = 0 points
sodium_lt_130_mmol_l_points_value = sodium_points(claim_sodium)
glucose_ge_250_mg_dl_or_ge_14_mmol_l_points_value = 0  # No = 0 points
hematocrit_lt_30_points_value = hematocrit_points(claim_hct)
partial_pressure_of_oxygen_lt_60_mm_hg_or_lt_8_kpa_points_value = 0  # No = 0 points
pleural_effusion_on_x_ray_points_value = 0  # No = 0 points

# Calculate total PSI score
total_psi_score = (age_points_value + sex_points_value +
                   nursing_home_resident_points_value +
                   neoplastic_disease_points_value +
                   liver_disease_history_points_value +
                   chf_history_points_value +
                   cerebrovascular_disease_history_points_value +
                   renal_disease_history_points_value +
                   altered_mental_status_points_value +
                   respiratory_rate_ge_30_points_value +
                   systolic_blood_pressure_lt_90_points_value +
                   temperature_lt_35_or_gt_39_9_points_value +
                   pulse_ge_125_points_value +
                   pH_lt_7_35_points_value +
                   bun_ge_30_mg_dl_or_ge_11_mmol_l_points_value +
                   sodium_lt_130_mmol_l_points_value +
                   glucose_ge_250_mg_dl_or_ge_14_mmol_l_points_value +
                   hematocrit_lt_30_points_value +
                   partial_pressure_of_oxygen_lt_60_mm_hg_or_lt_8_kpa_points_value +
                   pleural_effusion_on_x_ray_points_value +
                   history_of_severe_organ_insufficiency_points(claim_hosi) +
                   acute_renal_failure_points(claim_arf) +
                   confusion_points(False) +
                   dvt_signs_points(False))

# Accuracy criterion — rule-based → exact match
calc_correct = (total_psi_score == 16)

calculation = {
    "calculator_type": calculator_type,
    "formula":         formula,
    "substitution":    f"age_points_value = {age_points_direct(evidence_age)}
" +
                       f"sex_points_value = 0
" +
                       f"nursing_home_resident_points_value = 0
" +
                       f"neoplastic_disease_points_value = 0
" +
                       f"liver_disease_history_points_value = 0
" +
                       f"chf_history_points_value = 0
" +
                       f"cerebrovascular_disease_history_points_value = 0
" +
                       f"renal_disease_history_points_value = 0
" +
                       f"altered_mental_status_points_value = 0
" +
                       f"respiratory_rate_ge_30_points_value = {respiratory_rate_points(evidence_rr)}
" +
                       f"systolic_blood_pressure_lt_90_points_value = {systolic_blood_pressure_points(evidence_map)}
" +
                       f"temperature_lt_35_or_gt_39_9_points_value = {temperature_points(evidence_temp)}
" +
                       f"pulse_ge_125_points_value = {heart_rate_points(evidence_hr)}
" +
                       f"pH_lt_7_35_points_value = {ph_points(claim_ph)}
" +
                       f"bun_ge_30_mg_dl_or_ge_11_mmol_l_points_value = 0
" +
                       f"sodium_lt_130_mmol_l_points_value = {sodium_points(claim_sodium)}
" +
                       f"glucose_ge_250_mg_dl_or_ge_14_mmol_l_points_value = 0
" +
                       f"hematocrit_lt_30_points_value = {hematocrit_points(claim_hct)}
" +
                       f"partial_pressure_of_oxygen_lt_60_mm_hg_or_lt_8_kpa_points_value = 0
" +
                       f"pleural_effusion_on_x_ray_points_value = 0
" +
                       f"history_of_severe_organ_insufficiency_points = {history_of_severe_organ_insufficiency_points(claim_hosi)}
" +
                       f"acute_renal_failure_points = {acute_renal_failure_points(claim_arf)}
" +
                       f"confusion_points = {confusion_points(False)}
" +
                       f"dvt_signs_points = {dvt_signs_points(False)}
" +
                       f"total_psi_score = {total_psi_score}",
    "steps":           f"total_psi_score = {total_psi_score}",
    "correct_result":  f"{total_psi_score}",
    "claimed_result":  "16",
    "correct":         calc_correct,
}

# ── STEP 3: derive label ────────────────────────────────────────────────────
all_step1_correct = all(e["correct"] for e in entities)
if all_step1_correct and calc_correct:
    label = "true"
elif all_step1_correct and not calc_correct:
    label = "partially true"
else:
    label = "false"

print(json.dumps({
    "step1_entities":    entities,
    "step2_calculation": calculation,
    "step3_label":       label,
}))

