    "name": "Eye Response", "claim_value": "yes",
    "evidence_value": "yes", "correct": correct_eye_response
})

# Segment 2 — "the verbal_response is 2"
claim_verbal_response = 2
evidence_verbal_response = 2  # Inappropriate words = +3 points, Incomprehensible sounds = +2 points
correct_verbal_response = (claim_verbal_response == evidence_verbal_response)
entities.append({
    "name": "Verbal Response", "claim_value": "2",
    "evidence_value": "2", "correct": correct_verbal_response
})

