calculator_type = "rule-based"
formula = "GCS = Eye Response + Verbal Response + Motor Response"

# Best Eye Response: Spontaneously = +4 points, To verbal command = +3 points, To pain = +2 points, No eye opening = +1 point
if evidence_eye_response == "yes":
    eye_response_points = 4
elif evidence_eye_response == "to verbal command":
    eye_response_points = 3
elif evidence_eye_response == "to pain":
    eye_response_points = 2
else:
    eye_response_points = 1

# Best Verbal Response: Oriented = +5 points, Confused = +4 points, Inappropriate words = +3 points, Incomprehensible sounds = +2 points, No verbal response = +1 point
if evidence_verbal_response == "oriented":
    verbal_response_points = 5
elif evidence_verbal_response == "confused":
    verbal_response_points = 4
elif evidence_verbal_response == "inappropriate words":
    verbal_response_points = 3
elif evidence_verbal_response == "incomprehensible sounds":
    verbal_response_points = 2
else:
    verbal_response_points = 1

# Best Motor Response: Obeys commands = +6 points, Localizes pain = +5 points, Withdrawal from pain = +4 points, Flexion to pain = +3 points, Extension to pain = +2 points, No motor response = +1 point
if evidence_motor_response == "obeys commands":
    motor_response_points = 6
elif evidence_motor_response == "localizes pain":
    motor_response_points = 5
elif evidence_motor_response == "withdrawal from pain":
    motor_response_points = 4
elif evidence_motor_response == "flexion to pain":
    motor_response_points = 3
elif evidence_motor_response == "extension to pain":
    motor_response_points = 2
else:
    motor_response_points = 1

substitution = f"{eye_response_points} + {verbal_response_points} + {motor_response_points}"
correct_result_val = eye_response_points + verbal_response_points + motor_response_points
claimed_result_val = 5

# Accuracy criterion — rule-based → exact match
calc_correct = (correct_result_val == claimed_result_val)

calculation = {
    "calculator_type": calculator_type,
    "formula":         formula,
    "substitution":    substitution,
    "steps":           substitution,
    "correct_result":  f"{correct_result_val} points",
    "claimed_result":  f"{claimed_result_val} points",
    "correct":         calc_correct,
}

# ── STEP 3: derive label ────────────────────────────────────────────────────
all_step1_correct = all(e["correct"] for e in entities)
