total_score = bun_points + hemoglobin_points_men + systolic_bp_points + sex_points + heart_rate_points + melena_points + syncope_points + hepatic_disease_points + cardiac_failure_points

calculation = {
    "calculator_type": calculator_type,
    "formula":         formula,
    "substitution":    substitution,
    "steps":           f"{substitution} = {total_score}",
    "correct_result":  f"{total_score}",
    "claimed_result":  f"{10}",
    "correct":         (total_score == 10),
}

# ── STEP 3: derive label ────────────────────────────────────────────────────
all_step1_correct = all(e["correct"] for e in entities)
if all_step1_correct and calculation["correct"]:
    label = "true"
elif all_step1_correct and not calculation["correct"]:
    label = "partially true"
else:
    label = "false"

print(json.dumps({
    "step1_entities":    entities,
    "step2_calculation": calculation,
    "step3_label":       label,
}))

import json

# ── STEP 1: extract and verify every INPUT entity from the evidence ─────────
entities = []

# Segment 1 — "the eye_response is yes"
claim_eye_response = "yes"
evidence_eye_response = "yes"
correct_eye_response = (claim_eye_response == evidence_eye_response)
entities.append({
    "name": "Eye Response", "claim_value": "yes",
    "evidence_value": "yes", "correct": correct_eye_response
})

# Segment 2 — "the verbal_response is yes"
claim_verbal_response = "yes"
evidence_verbal_response = "yes"
correct_verbal_response = (claim_verbal_response == evidence_verbal_response)
entities.append({
    "name": "Verbal Response", "claim_value": "yes",
    "evidence_value": "yes", "correct": correct_verbal_response
})

# Segment 3 — "the motor_response is 2"
claim_motor_response = 2
evidence_motor_response = 2
correct_motor_response = (claim_motor_response == evidence_motor_response)
entities.append({
    "name": "Motor Response", "claim_value": "2",
    "evidence_value": "2", "correct": correct_motor_response
})

# ── STEP 2: calculate using evidence values ─────────────────────────────────
# Formula: GCS = Eye Response + Verbal Response + Motor Response
calculator_type = "rule-based"
formula = "Glasgow Coma Score (GCS) = Eye Response + Verbal Response + Motor Response"

# Best Eye Response: Spontaneously = +4 points, To verbal command = +3 points, To pain = +2 points, No eye opening = +1 point
if evidence_eye_response == "yes":
    eye_response_points = 4
elif evidence_eye_response == "to verbal command":
    eye_response_points = 3
elif evidence_eye_response == "to pain":
    eye_response_points = 2
else:
    eye_response_points = 1

# Best Verbal Response: Oriented = +5 points, Confused = +4 points, Inappropriate words = +3 points, Incomprehensible sounds = +2 points, No verbal response = +1 point
if evidence_verbal_response == "yes":
    verbal_response_points = 5
elif evidence_verbal_response == "confused":
    verbal_response_points = 4
elif evidence_verbal_response == "inappropriate words":
    verbal_response_points = 3
elif evidence_verbal_response == "incomprehensible sounds":
    verbal_response_points = 2
else:
    verbal_response_points = 1

# Best Motor Response: Obeys commands = +6 points, Localizes pain = +5 points, Withdrawal from pain = +4 points, Flexion to pain = +3 points, Extension to pain = +2 points, No motor response = +1 point
if evidence_motor_response == 6:
    motor_response_points = 6
elif evidence_motor_response == 5:
    motor_response_points = 5
elif evidence_motor_response == 4:
    motor_response_points = 4
elif evidence_motor_response == 3:
    motor_response_points = 3
elif evidence_motor_response == 2:
    motor_response_points = 2
else:
    motor_response_points = 1

# Accuracy criterion — rule-based → exact match
gcs_score = eye_response_points + verbal_response_points + motor_response_points
claimed_gcs_score = 5

calculation = {
    "calculator_type": calculator_type,
    "formula":         formula,
    "substitution":    f"{eye_response_points} + {verbal_response_points} + {motor_response_points}",
    "steps":           f"{eye_response_points} + {verbal_response_points} + {motor_response_points} = {gcs_score}",
    "correct_result":  f"{gcs_score}",
    "claimed_result":  f"{claimed_gcs_score}",
    "correct":         (gcs_score == claimed_gcs_score),
}

# ── STEP 3: derive label ────────────────────────────────────────────────────
all_step1_correct = all(e["correct"] for e in entities)
if all_step1_correct and calculation["correct"]:
    label = "true"
elif all_step1_correct and not calculation["correct"]:
    label = "partially true"
else:
    label = "false"

print(json.dumps({
    "step1_entities":    entities,
    "step2_calculation": calculation,
    "step3_label":       label,
}))
